// Examples generator. See scripts/examples-gen/README.md for the story
// contract and the path-derivation rules. Entry point: `npm run examples:generate`.
//
// Reads:
//   - examples/stories/**/*.story.ts       (each story = one rendered example)
//   - examples/dev-tools/demo-spec.ts      (typed contract for stories)
//
// Writes (each marked @generated):
//   - examples/src/app/features/<mirrored-path>.component.ts  (one per story)
//   - examples/src/app/app.routes.ts
//   - examples/src/app/_routes-meta.ts

import { readFile, writeFile, readdir, mkdir, rm } from 'node:fs/promises';
import { join, relative, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, '..', '..');
const STORIES_ROOT = join(ROOT, 'examples', 'stories');
const EXAMPLES_APP = join(ROOT, 'examples', 'src', 'app');
const FEATURES_DIR = join(EXAMPLES_APP, 'features');

const GEN_HEADER = '// @generated by example-generator — do not edit manually';

// Generic helpers

function kebabToPascal(s) {
  return s
    .split('-')
    .map((p) => p.charAt(0).toUpperCase() + p.slice(1))
    .join('');
}

function slugify(s) {
  return s
    .toLowerCase()
    .replaceAll(/[^a-z0-9]+/g, '-')
    .replaceAll(/(^-|-$)/g, '');
}

function tsQuote(s) {
  return (
    "'" +
    String(s)
      .replaceAll('\\', '\\\\')
      .replaceAll("'", String.raw`\'`) +
    "'"
  );
}

function stripCommentsForScan(s) {
  return String(s ?? '')
    .replace(/\/\*[\s\S]*?\*\//g, '')
    .replace(/\/\/[^\n]*/g, '');
}

function backtickEscape(s) {
  return String(s).replaceAll('\\', '\\\\').replaceAll('`', '\\`').replaceAll('${', '\\${');
}

/**
 * Strip demo-chrome divs from a displayed template — `event-grid`/`event-row`
 * (state readouts), `button-row`/`status-row` (config toggles), `cngx-ex-chrome`
 * (explicit opt-in marker). Walks balanced <div>/</div> so nested chrome
 * inside an outer chrome block is removed together. The live rendered
 * template keeps everything; this only affects the Template-panel display
 * and complements the `templateChrome` field for sections that haven't
 * been migrated to the split yet.
 */
function stripDemoChrome(html) {
  const opener =
    /<div\b[^>]*\bclass=["'][^"']*\b(?:event-grid|event-row|button-row|status-row|cngx-ex-chrome)\b[^"']*["'][^>]*>/g;
  let result = html;
  while (true) {
    opener.lastIndex = 0;
    const m = opener.exec(result);
    if (!m) break;
    let depth = 1;
    let i = m.index + m[0].length;
    while (i < result.length && depth > 0) {
      const next = result.slice(i).match(/<\/?div\b[^>]*>/);
      if (!next) break;
      const absIdx = i + next.index;
      if (next[0].startsWith('</')) depth--;
      else depth++;
      i = absIdx + next[0].length;
    }
    result = result.slice(0, m.index).replace(/\s*$/, '') + result.slice(i);
  }
  return result;
}

function dedent(s) {
  const lines = String(s).split('\n');
  const meaningful = lines.filter((l) => l.trim().length > 0);
  if (meaningful.length === 0) return '';
  let minIndent = Infinity;
  for (const l of meaningful) {
    const m = new RegExp(/^[ \t]*/).exec(l);
    minIndent = Math.min(minIndent, m[0].length);
  }
  if (!Number.isFinite(minIndent) || minIndent === 0) {
    return s.replace(/^\s*\n/, '').replace(/\s+$/, '');
  }
  return lines
    .map((l) => l.slice(minIndent))
    .join('\n')
    .replace(/^\s*\n/, '')
    .replace(/\s+$/, '');
}

// Allowlist of inline-formatting tags that may appear in story `description`
// / `subtitle` prose and pass through to the rendered _exDescription /
// _exSubtitle interpolations. Everything else gets its `<` escaped to `&lt;`
// so accidental references to custom elements (`<cngx-foo>`) or other markup
// in prose render as text instead of broken HTML.
//
// Security is handled at runtime by Angular's DomSanitizer on the
// `[innerHTML]` binding — scripts, inline event handlers, and unsafe URLs
// are stripped regardless of what arrives here. This filter exists for
// content-correctness, not security.
const ALLOWED_PAIRED_TAGS = [
  'code',
  'pre',
  'em',
  'strong',
  'b',
  'i',
  'kbd',
  'mark',
  'small',
  'sub',
  'sup',
  'var',
  'samp',
  'del',
  'ins',
  'abbr',
  'q',
  'cite',
  'a',
];
const ALLOWED_VOID_TAGS = ['br', 'wbr'];

function escapeCustomElementTags(html) {
  if (!html) return '';
  const parts = [];
  let i = 0;
  const pairedAlt = ALLOWED_PAIRED_TAGS.join('|');
  const voidAlt = ALLOWED_VOID_TAGS.join('|');
  // Each match is either a paired tag with content + closing, or a void tag.
  const re = new RegExp(
    `<(${pairedAlt})\\b[^>]*>[\\s\\S]*?<\\/\\1>|<(${voidAlt})\\b[^>]*\\/?>`,
    'gi',
  );
  let m;
  while ((m = re.exec(html)) !== null) {
    parts.push({ kind: 'escape', text: html.slice(i, m.index) });
    parts.push({ kind: 'verbatim', text: m[0] });
    i = m.index + m[0].length;
  }
  parts.push({ kind: 'escape', text: html.slice(i) });
  return parts
    .map((p) => (p.kind === 'verbatim' ? p.text : p.text.replaceAll('<', '&lt;')))
    .join('');
}

// File walking

async function* walkFiles(dir, predicate) {
  let entries;
  try {
    entries = await readdir(dir, { withFileTypes: true });
  } catch {
    return;
  }
  for (const ent of entries) {
    const full = join(dir, ent.name);
    if (ent.isDirectory()) {
      yield* walkFiles(full, predicate);
    } else if (ent.isFile() && predicate(full)) {
      yield full;
    }
  }
}

// public-api / selector maps

/** Well-known Angular symbols → their module path. */
const KNOWN_ANGULAR_IMPORTS = new Map([
  ['AsyncPipe', '@angular/common'],
  ['DatePipe', '@angular/common'],
  ['DecimalPipe', '@angular/common'],
  ['JsonPipe', '@angular/common'],
  ['KeyValuePipe', '@angular/common'],
  ['LowerCasePipe', '@angular/common'],
  ['NgClass', '@angular/common'],
  ['NgStyle', '@angular/common'],
  ['NgTemplateOutlet', '@angular/common'],
  ['PercentPipe', '@angular/common'],
  ['SlicePipe', '@angular/common'],
  ['TitleCasePipe', '@angular/common'],
  ['UpperCasePipe', '@angular/common'],
  ['CurrencyPipe', '@angular/common'],
  ['FormsModule', '@angular/forms'],
  ['ReactiveFormsModule', '@angular/forms'],
  ['RouterLink', '@angular/router'],
  ['RouterLinkActive', '@angular/router'],
  ['RouterOutlet', '@angular/router'],
  ['MatAutocompleteModule', '@angular/material/autocomplete'],
  ['MatBadgeModule', '@angular/material/badge'],
  ['MatButtonModule', '@angular/material/button'],
  ['MatCardModule', '@angular/material/card'],
  ['MatCheckboxModule', '@angular/material/checkbox'],
  ['MatChipsModule', '@angular/material/chips'],
  ['MatDialogModule', '@angular/material/dialog'],
  ['MatDividerModule', '@angular/material/divider'],
  ['MatExpansionModule', '@angular/material/expansion'],
  ['MatFormFieldModule', '@angular/material/form-field'],
  ['MatIconModule', '@angular/material/icon'],
  ['MatInputModule', '@angular/material/input'],
  ['MatListModule', '@angular/material/list'],
  ['MatMenuModule', '@angular/material/menu'],
  ['MatPaginatorModule', '@angular/material/paginator'],
  ['MatProgressBarModule', '@angular/material/progress-bar'],
  ['MatProgressSpinnerModule', '@angular/material/progress-spinner'],
  ['MatRadioModule', '@angular/material/radio'],
  ['MatRippleModule', '@angular/material/core'],
  ['MatSelectModule', '@angular/material/select'],
  ['MatSidenavModule', '@angular/material/sidenav'],
  ['MatSlideToggleModule', '@angular/material/slide-toggle'],
  ['MatSnackBarModule', '@angular/material/snack-bar'],
  ['MatSortModule', '@angular/material/sort'],
  ['MatStepperModule', '@angular/material/stepper'],
  ['MatTableModule', '@angular/material/table'],
  ['MatTabsModule', '@angular/material/tabs'],
  ['MatToolbarModule', '@angular/material/toolbar'],
  ['MatTooltipModule', '@angular/material/tooltip'],
]);

async function buildPublicApiImportMap() {
  const map = new Map(KNOWN_ANGULAR_IMPORTS);
  const apis = [];
  for await (const f of walkFiles(join(ROOT, 'projects'), (p) => p.endsWith('/public-api.ts'))) {
    apis.push(relative(ROOT, f));
  }
  for (const rel of apis) {
    const parts = rel.split('/').slice(1, -1);
    if (parts[0] === 'testing') continue;
    const pkg = '@cngx/' + parts.join('/');
    const src = await readFile(join(ROOT, rel), 'utf8');
    for (const m of src.matchAll(/export\s*\{([^}]+)\}/g)) {
      for (const raw of m[1].split(',')) {
        const id = raw
          .trim()
          .replace(/^type\s+/, '')
          .split(/\s+as\s+/)[0]
          ?.trim();
        if (id && /^[A-Z_]/.test(id)) {
          if (!map.has(id)) map.set(id, pkg);
        }
      }
    }
  }
  return map;
}

async function buildSelectorMap() {
  const map = new Map();
  for await (const file of walkFiles(
    join(ROOT, 'projects'),
    (p) => p.endsWith('.ts') && !p.endsWith('.spec.ts') && !p.endsWith('public-api.ts'),
  )) {
    let src;
    try {
      src = await readFile(file, 'utf8');
    } catch {
      continue;
    }
    for (const classMatch of src.matchAll(/\bexport\s+(?:abstract\s+)?class\s+([A-Z]\w*)/g)) {
      const className = classMatch[1];
      const before = src.slice(0, classMatch.index);
      const selectorMatches = [...before.matchAll(/selector:\s*['"]([^'"]+)['"]/g)];
      const exportAsMatches = [...before.matchAll(/exportAs:\s*['"]([^'"]+)['"]/g)];
      if (selectorMatches.length === 0 && exportAsMatches.length === 0) continue;
      const selectors = [];
      if (selectorMatches.length > 0) {
        const last = selectorMatches.at(-1);
        selectors.push(
          ...last[1]
            .split(',')
            .map((s) => s.trim())
            .filter(Boolean),
        );
      }
      if (exportAsMatches.length > 0) {
        const last = exportAsMatches.at(-1);
        selectors.push(
          ...last[1]
            .split(',')
            .map((s) => s.trim())
            .filter(Boolean),
        );
      }
      const existing = map.get(className) ?? [];
      map.set(className, [...new Set([...existing, ...selectors])]);
    }
  }
  return map;
}

// Story loading

async function loadStory(storyPath) {
  const content = await readFile(storyPath, 'utf8');
  const stripped = content.replace(/^import type[^\n]+\n/m, '');
  const match = stripped.match(/export const STORY[^=]*=\s*([\s\S]+?);?\s*$/);
  if (!match) throw new Error(`No STORY export in ${storyPath}`);
  return new Function(`return (${match[1]})`)();
}

function importedSymbols(importLine) {
  const m = importLine.match(/import\s+(?:type\s+)?\{([^}]+)\}/);
  if (!m) return [];
  return m[1]
    .split(',')
    .map((s) => {
      const parts = s
        .trim()
        .replace(/^type\s+/, '')
        .split(/\s+as\s+/);
      return (parts.length > 1 ? parts[1] : parts[0])?.trim();
    })
    .filter(Boolean);
}

// Component imports

function buildImports(story, importMap, featureDepth) {
  // Imports are scanned against the LIVE class — setup + setupChrome —
  // because both halves end up in the class body. The displayed _exTs
  // panel (see emitComponentSource) re-filters against `setup` alone.
  const setup = stripCommentsForScan((story.setup ?? '') + '\n' + (story.setupChrome ?? ''));
  const tpl =
    (story.template ?? '') +
    '\n' +
    (story.templateChrome ?? '') +
    '\n' +
    (story.templateChromeBefore ?? '');

  const usesSignal = /\bsignal\s*[<(]/.test(setup);
  const usesComputed = /\bcomputed\s*[<(]/.test(setup);
  const usesInject = /\binject\s*\(/.test(setup);
  const usesAfterRender = /\bafterNextRender\s*\(/.test(setup);
  const usesEffect = /\beffect\s*\(/.test(setup);
  const usesViewChild = /\bviewChild\b/.test(setup);
  const usesElementRef = /\bElementRef\b/.test(setup);
  const usesDestroyRef = /\bDestroyRef\b/.test(setup);
  const usesUntracked = /\buntracked\s*\(/.test(setup);
  const usesLinkedSignal = /\blinkedSignal\s*[<(]/.test(setup);

  const coreSymbols = [
    'ChangeDetectionStrategy',
    'Component',
    ...(usesAfterRender ? ['afterNextRender'] : []),
    ...(usesComputed ? ['computed'] : []),
    ...(usesDestroyRef ? ['DestroyRef'] : []),
    ...(usesEffect ? ['effect'] : []),
    ...(usesElementRef ? ['ElementRef'] : []),
    ...(usesInject ? ['inject'] : []),
    ...(usesLinkedSignal ? ['linkedSignal'] : []),
    ...(usesSignal ? ['signal'] : []),
    ...(usesUntracked ? ['untracked'] : []),
    ...(usesViewChild ? ['viewChild'] : []),
  ];

  const coreLine = `import { ${coreSymbols.join(', ')} } from '@angular/core';`;

  const scanText = setup + '\n' + tpl;
  const explicitRefs = new Set([...(story.imports ?? []), ...(story.hostDirectives ?? [])]);

  function isReferenced(id) {
    if (explicitRefs.has(id)) return true;
    const re = new RegExp(String.raw`\b${id.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\b`);
    return re.test(scanText);
  }

  function filterImportLine(line) {
    const match = line.match(
      /^(\s*import\s*(?:type\s+)?\{)([^}]+)(\}\s*from\s*['"][^'"]+['"];?\s*)$/,
    );
    if (!match) return line;
    const [, head, body, tail] = match;
    const kept = body
      .split(',')
      .map((s) => s.trim())
      .filter(Boolean)
      .filter((spec) => {
        const parts = spec.replace(/^type\s+/, '').split(/\s+as\s+/);
        const id = (parts.length > 1 ? parts[1] : parts[0])?.trim();
        return isReferenced(id);
      });
    if (kept.length === 0) return null;
    return `${head} ${kept.join(', ')} ${tail.trim()}`;
  }

  const upPrefix = '../'.repeat(featureDepth);
  const fixturesUpPrefix = '../'.repeat(featureDepth + 2);
  function rewritePaths(line) {
    if (!line) return line;
    if (/'(?:\.\.\/)+_fixtures\//.test(line)) {
      return line.replace(/'(?:\.\.\/)+_fixtures\/([^']+)'/, `'${upPrefix}_fixtures/$1'`);
    }
    return line.replace(/'(?:\.\.\/)+([^']*fixtures(?:[^']*)?)'/, `'${fixturesUpPrefix}fixtures'`);
  }

  const filteredModuleImports = (story.moduleImports ?? [])
    .filter((l) => !/from\s*['"]@angular\/core['"]/.test(l))
    .map(filterImportLine)
    .filter((l) => l !== null)
    .map(rewritePaths);

  const coveredIds = new Set();
  for (const line of filteredModuleImports) {
    for (const id of importedSymbols(line)) coveredIds.add(id);
  }

  const candidates = new Set([...(story.imports ?? []), ...(story.hostDirectives ?? [])]);
  for (const m of setup.matchAll(/\b([A-Z][A-Za-z0-9_]*)\b/g)) {
    candidates.add(m[1]);
  }

  const extraByPkg = new Map();
  for (const id of candidates) {
    if (coveredIds.has(id)) continue;
    const pkg = importMap.get(id);
    if (!pkg) continue;
    if (!extraByPkg.has(pkg)) extraByPkg.set(pkg, new Set());
    extraByPkg.get(pkg).add(id);
  }
  const extraLines = [...extraByPkg.entries()].map(
    ([pkg, ids]) => `import { ${[...ids].sort().join(', ')} } from '${pkg}';`,
  );

  return { lines: [coreLine, ...filteredModuleImports, ...extraLines] };
}

// Tag rendering

function buildTagPairs(story) {
  const pairs = [];
  if (story.level) pairs.push(['atomic-level', story.level]);
  for (const a of story.audience ?? []) pairs.push(['audience', a]);
  if (story.artifact) pairs.push(['artifact', story.artifact]);
  for (const f of story.focus ?? []) pairs.push(['focus', f]);
  if (story.stability && story.stability !== 'stable') {
    pairs.push(['stability', story.stability]);
  }
  if (story.framework) pairs.push(['framework', story.framework]);
  return pairs;
}

// Emit component source

function indent(s, n) {
  const pad = ' '.repeat(n);
  return s
    .split('\n')
    .map((l) => (l.length ? pad + l : l))
    .join('\n');
}

function emitComponentSource(meta, story, importMap) {
  const { lines } = buildImports(story, importMap, meta.featureDepth);

  const tpl =
    (story.template ?? '') +
    '\n' +
    (story.templateChrome ?? '') +
    '\n' +
    (story.templateChromeBefore ?? '');
  const tplImports = (story.imports ?? []).filter((cls) => {
    if (!cls.startsWith('Cngx')) return true;
    if (new RegExp(String.raw`\b${cls}\b`).test(tpl)) return true;
    const selectors = meta.selectorMap?.get(cls) ?? [];
    if (selectors.length === 0) return true;
    for (const sel of selectors) {
      const elementMatch = sel.match(/^[a-z][a-z0-9-]*$/);
      if (elementMatch) {
        if (new RegExp(`<${sel}(?![a-z0-9-])`).test(tpl)) return true;
        continue;
      }
      const attrMatch = sel.match(/^\[([\w-]+)(?:[*~|^$]?=[^\]]*)?\]$/);
      if (attrMatch) {
        if (new RegExp(String.raw`\b${attrMatch[1]}\b`).test(tpl)) return true;
        continue;
      }
      const compoundMatch = sel.match(/^([a-z][a-z0-9-]*)\[([\w-]+)(?:[*~|^$]?=[^\]]*)?\]$/);
      if (compoundMatch) {
        const [, tag, attr] = compoundMatch;
        const tagOpenRe = new RegExp(String.raw`<${tag}\b[^>]*\b${attr}\b`);
        if (tagOpenRe.test(tpl)) return true;
        continue;
      }
      if (tpl.includes(sel)) return true;
    }
    return false;
  });
  const decoratorImports = tplImports.length > 0 ? `\n  imports: [${tplImports.join(', ')}],` : '';

  const storyHostDirectives = (story.hostDirectives ?? []).filter(Boolean);
  const decoratorHostDirectives =
    storyHostDirectives.length > 0
      ? `\n  hostDirectives: [${storyHostDirectives.join(', ')}],`
      : '';

  // Live class body — setup (artifact code) + setupChrome (instrumentation).
  // The displayed _exTs panel below shows setup only.
  const liveSetup = [story.setup ?? '', story.setupChrome ?? '']
    .map((s) => s.trim())
    .filter(Boolean)
    .join('\n\n');
  const setupBody = liveSetup
    .split('\n')
    .map((l) => (l.trim() ? '  ' + l : ''))
    .join('\n');

  const tagPairs = buildTagPairs(story);
  const tagFieldEntries = tagPairs
    .map(([dim, value]) => `{ dim: ${tsQuote(dim)}, value: ${tsQuote(value)} }`)
    .join(', ');
  const refEntries = ((story.references ?? []) || [])
    .map(({ label, href }) => `{ label: ${tsQuote(label)}, href: ${tsQuote(href)} }`)
    .join(', ');
  const introFields = [
    `  protected readonly _exTitle: string = ${tsQuote(story.title ?? '')};`,
    `  protected readonly _exDescription: string = ${tsQuote(escapeCustomElementTags(story.description ?? ''))};`,
    `  protected readonly _exSubtitle: string = ${tsQuote(escapeCustomElementTags(story.subtitle ?? ''))};`,
    `  protected readonly _exTags: readonly { dim: string; value: string }[] = [${tagFieldEntries}];`,
    `  protected readonly _exRefs: readonly { label: string; href: string }[] = [${refEntries}];`,
  ].join('\n');

  // Displayed _exTs: filter imports a SECOND time against `setup` only.
  // The earlier buildImports() scanned setup + setupChrome to keep the live
  // class compiling; here we re-scan to drop imports the chrome-only code
  // would have needed (rxjs `delay`, fail-flag helpers, log buffers, etc.).
  const setupOnlyScan = stripCommentsForScan(story.setup ?? '') + '\n' + (story.template ?? '');
  const sourceImports = lines
    .filter((l) => !l.includes("from '@angular/core'"))
    .map((line) => {
      const match = line.match(
        /^(\s*import\s*(?:type\s+)?\{)([^}]+)(\}\s*from\s*['"][^'"]+['"];?\s*)$/,
      );
      if (!match) return line;
      const [, head, body, tail] = match;
      const kept = body
        .split(',')
        .map((s) => s.trim())
        .filter(Boolean)
        .filter((spec) => {
          const parts = spec.replace(/^type\s+/, '').split(/\s+as\s+/);
          const id = (parts.length > 1 ? parts[1] : parts[0])?.trim();
          if ((story.imports ?? []).includes(id)) return true;
          return new RegExp(String.raw`\b${id.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\b`).test(
            setupOnlyScan,
          );
        });
      if (kept.length === 0) return null;
      return `${head} ${kept.join(', ')} ${tail.trim()}`;
    })
    .filter((l) => l !== null)
    .join('\n')
    .trim();
  const dedentedSetup = dedent(story.setup ?? '');
  const sourceTs = [sourceImports, dedentedSetup].filter(Boolean).join('\n\n').trim();
  // Strip chrome blocks from the displayed template. Even when a story has
  // migrated chrome into `templateChrome`, stray button-row blocks in the
  // remaining `template` are still scrubbed defensively.
  const sourceHtml = dedent(stripDemoChrome(story.template));
  const sourceFields = [
    `  protected readonly _exTs: string = \`${backtickEscape(sourceTs)}\`;`,
    `  protected readonly _exHtml: string = \`${backtickEscape(sourceHtml)}\`;`,
  ].join('\n');

  const intro = [
    `    <header class="cngx-ex-intro">`,
    `      @if (_exTitle) { <h1>{{ _exTitle }}</h1> }`,
    `      @if (_exTags.length > 0) {`,
    `        <ul class="cngx-ex-tags" aria-label="Tags">`,
    `          @for (t of _exTags; track t.dim + ':' + t.value) {`,
    `            <li class="cngx-ex-tag" [attr.data-dim]="t.dim" [attr.data-value]="t.value">{{ t.value }}</li>`,
    `          }`,
    `        </ul>`,
    `      }`,
    `      @if (_exDescription) { <p [innerHTML]="_exDescription"></p> }`,
    `      @if (_exSubtitle) { <p class="cngx-ex-hint" [innerHTML]="_exSubtitle"></p> }`,
    `      @if (_exRefs.length > 0) {`,
    `        <ul class="cngx-ex-refs" aria-label="Implements">`,
    `          @for (r of _exRefs; track r.href) {`,
    `            <li class="cngx-ex-ref"><a [href]="r.href" target="_blank" rel="noopener">{{ r.label }}</a></li>`,
    `          }`,
    `        </ul>`,
    `      }`,
    `    </header>`,
  ].join('\n');

  const sourceBlocks = [
    `    <details class="cngx-ex-code">`,
    `      <summary>TypeScript</summary>`,
    `      <pre><code>{{ _exTs }}</code></pre>`,
    `    </details>`,
    `    <details class="cngx-ex-code">`,
    `      <summary>Template</summary>`,
    `      <pre><code>{{ _exHtml }}</code></pre>`,
    `    </details>`,
  ].join('\n');

  // Live template — wrap the artifact and (optional) chrome in their own
  // sections so the styles can space them apart, and wrap the demo body in
  // <main> so Lighthouse / a11y tooling sees the landmark it expects.
  const escape = (s) => s.replaceAll('`', '\\`').replaceAll('${', '\\${');
  const artifact = escape((story.template ?? '').trim());
  const chrome = escape((story.templateChrome ?? '').trim());
  const chromeBefore = escape((story.templateChromeBefore ?? '').trim());
  const artifactBlock = `<section class="cngx-ex-artifact">\n${indent(artifact, 2)}\n</section>`;
  const chromeBlock = chrome
    ? `<section class="cngx-ex-chrome">\n${indent(chrome, 2)}\n</section>`
    : '';
  const chromeBeforeBlock = chromeBefore
    ? `<section class="cngx-ex-chrome cngx-ex-chrome--before">\n${indent(chromeBefore, 2)}\n</section>`
    : '';
  const mainBody = [chromeBeforeBlock, artifactBlock, chromeBlock, sourceBlocks.replace(/^    /gm, '')]
    .filter(Boolean)
    .join('\n');

  return `${GEN_HEADER}
// Source: ${meta.storyRelPath}

${lines.join('\n')}

@Component({
  selector: '${meta.selector}',
  changeDetection: ChangeDetectionStrategy.OnPush,${decoratorImports}${decoratorHostDirectives}
  template: \`
${intro}
    <main>
${indent(mainBody, 6)}
    </main>
  \`,
})
export class ${meta.className} {
${introFields}
${sourceFields}${setupBody ? '\n' + setupBody : ''}
}
`;
}

// Routes

function emitRoutesSource(routes) {
  const sorted = [...routes].sort((a, b) => a.path.localeCompare(b.path));
  const entries = sorted
    .map((r) =>
      [
        `  {`,
        `    path: '${r.path}',`,
        `    loadComponent: () => import('${r.importPath}').then((m) => m.${r.className}),`,
        `    data: { lib: '${r.lib}', category: '${r.category}', title: ${JSON.stringify(r.title)} },`,
        `  },`,
      ].join('\n'),
    )
    .join('\n');

  return `${GEN_HEADER}
import type { Routes } from '@angular/router';

export const routes: Routes = [
${entries}
  {
    path: '',
    loadComponent: () => import('./home/home.component').then((m) => m.HomeComponent),
  },
  { path: '**', redirectTo: '' },
];
`;
}

function emitRoutesMetaSource(routes) {
  const sorted = [...routes].sort((a, b) => a.path.localeCompare(b.path));
  const entries = sorted
    .map(
      (r) =>
        `  ${JSON.stringify({
          path: r.path,
          lib: r.lib,
          category: r.category,
          pathSegments: r.pathSegments,
          title: r.title,
          apiComponents: r.apiComponents,
          level: r.level ?? null,
          audience: r.audience,
          artifact: r.artifact ?? null,
          focus: r.focus,
          stability: r.stability ?? null,
          framework: r.framework ?? null,
        })},`,
    )
    .join('\n');
  return `${GEN_HEADER}
export interface RouteMeta {
  path: string;
  lib: string;
  category: string;
  pathSegments: string[];
  title: string;
  apiComponents: string[];
  level: 'atom' | 'molecule' | 'organism' | null;
  audience: ('dev' | 'design' | 'a11y')[];
  artifact: 'standalone' | 'building-block' | null;
  focus: ('visual-variants' | 'behavior' | 'a11y-pattern' | 'integration' | 'error-handling' | 'async-state' | 'composition')[];
  stability: 'stable' | 'experimental' | 'deprecated' | null;
  framework: 'signal-forms' | 'reactive-forms' | 'template-only' | 'programmatic' | null;
}

export const ROUTES_META: readonly RouteMeta[] = [
${entries}
];
`;
}

// Reset

async function resetFeaturesDir() {
  await rm(FEATURES_DIR, { recursive: true, force: true });
  await mkdir(FEATURES_DIR, { recursive: true });
}

// Main

async function main() {
  await resetFeaturesDir();

  const importMap = await buildPublicApiImportMap();
  const selectorMap = await buildSelectorMap();

  const routes = [];
  const helperFilesCopied = new Set();

  for await (const storyPath of walkFiles(STORIES_ROOT, (p) => p.endsWith('.story.ts'))) {
    const relPath = relative(STORIES_ROOT, storyPath);
    const pathSegments = relPath.split('/');
    const fileBase = pathSegments.pop().replace(/\.story\.ts$/, '');
    const lib = pathSegments[0] ?? '';
    const category = pathSegments[1] ?? '';
    const folderLeaf = pathSegments.at(-1) ?? lib;

    let story;
    try {
      story = await loadStory(storyPath);
    } catch (err) {
      console.warn(`Skipping ${relPath}: ${err.message}`);
      continue;
    }

    const featureDir = join(FEATURES_DIR, ...pathSegments);
    await mkdir(featureDir, { recursive: true });

    const sourceDir = dirname(storyPath);
    const helperRefs = new Set();
    for (const line of story.moduleImports ?? []) {
      const m = line.match(/from\s+['"](\.\/[^'"]+)['"]/);
      if (m) helperRefs.add(m[1]);
    }
    for (const rel of helperRefs) {
      const helperKey = featureDir + '|' + rel;
      if (helperFilesCopied.has(helperKey)) continue;
      const candidates = [join(sourceDir, rel + '.ts'), join(sourceDir, rel)];
      for (const candidate of candidates) {
        try {
          const content = await readFile(candidate, 'utf8');
          const destName = rel.replace(/^\.\//, '') + (candidate.endsWith('.ts') ? '.ts' : '');
          await writeFile(join(featureDir, destName), content);
          helperFilesCopied.add(helperKey);
          break;
        } catch {
          /* try next */
        }
      }
    }

    const selector = 'app-' + slugify(folderLeaf) + '-' + slugify(fileBase);
    const className = kebabToPascal(folderLeaf) + kebabToPascal(fileBase);
    const routePath = [...pathSegments, fileBase].join('/');
    const featureDepth = pathSegments.length + 1;

    const code = emitComponentSource(
      {
        storyRelPath: 'examples/stories/' + relPath,
        selector,
        className,
        featureDepth,
        selectorMap,
      },
      story,
      importMap,
    );
    await writeFile(join(featureDir, `${fileBase}.component.ts`), code);

    routes.push({
      path: routePath,
      importPath: './features/' + [...pathSegments, fileBase].join('/') + '.component',
      className,
      lib,
      category,
      pathSegments,
      title: story.title,
      apiComponents: story.apiComponents ?? [],
      level: story.level,
      audience: story.audience ?? [],
      artifact: story.artifact,
      focus: story.focus ?? [],
      stability: story.stability,
      framework: story.framework,
    });
  }

  await writeFile(join(EXAMPLES_APP, 'app.routes.ts'), emitRoutesSource(routes));
  await writeFile(join(EXAMPLES_APP, '_routes-meta.ts'), emitRoutesMetaSource(routes));

  console.log(`Wrote ${routes.length} routes from ${routes.length} stories.`);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
